// AuthContext.js
import React, { createContext, useState, useContext } from 'react';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);  // Состояние пользователя

  const login = (username, password) => {
    // Здесь должна быть проверка на сервере, но для примера будем считать, что логин успешен
    setUser({ username }); // Сохраняем данные о пользователе
  };

  const logout = () => {
    setUser(null); // Удаляем пользователя
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}
